// Validate input + parse
const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const lead_id = body.lead_id || null;
const stage_hint = body.stage_hint || null;
const situation_hint = body.situation_hint || '';
const token = body.token || null;
const client_id = body.client_id || null;

if (!lead_id) {
  return { json: { _error: true, error: 'lead_id is required', ok: false } };
}
if (!token) {
  return { json: { _error: true, error: 'token is required (dashboard_token or admin token)', ok: false } };
}

// Token verification is a TODO — wire to clx-verify-dashboard-access-v1 at activation.
// For now: accept presence of token; RLS on the scripts tables + service_role key on Supabase
// node protects the library. No data is returned from this workflow until the Fetch Lead step
// resolves, and that step will fail if RLS rejects the caller.

return { json: { lead_id, stage_hint, situation_hint, token, client_id, _ok: true } };

// Resolve niche from lead or client. Normalize stage hint to lowercase.
const leadArr = $input.item.json || [];
const lead = Array.isArray(leadArr) && leadArr.length > 0 ? leadArr[0] : null;
const parsed = $('Validate + Parse').first().json;

if (!lead) {
  return { json: { _error: true, error: 'lead not found or RLS rejected request', ok: false, lead_id: parsed.lead_id } };
}

const client = lead.clients || {};
const niche = lead.niche || client.niche_name || client.vertical || lead.vertical || lead.industry || null;
const stage = (parsed.stage_hint || '').toLowerCase() || null;

return { json: {
  lead_id: lead.id,
  client_id: lead.client_id,
  niche,
  stage,
  situation_hint: parsed.situation_hint || '',
  lead_ctx: {
    name: ((lead.first_name || '') + ' ' + (lead.last_name || '')).trim(),
    company: lead.company || '',
    city: lead.city || '',
    province: lead.province || '',
    niche,
    lead_score: lead.lead_score || null,
    lead_status: lead.lead_status || null,
    product_type: lead.product_type || null,
    notes: (lead.notes || '').slice(0, 400)
  },
  client_ctx: {
    client_name: client.client_name || '',
    vertical: client.vertical || client.niche_name || null,
    calendly_link: client.calendly_link || ''
  }
} };

// Bucket candidates + build Claude prompt
const rpcRows = Array.isArray($input.item.json) ? $input.item.json : [];
const ctx = $('Resolve Context').first().json;

const buckets = { discovery: [], objection: [], closing: [], followup: [], competitor: [] };
for (const r of rpcRows) {
  const cat = (r.script_category || '').toLowerCase();
  if (buckets[cat]) buckets[cat].push(r);
}

const system_prompt = [
  'You are Crystallux Closing Intelligence Copilot.',
  'You rank pre-written sales scripts against a specific lead + situation.',
  'Rules:',
  ' - Output STRICT JSON only. No prose outside the JSON.',
  ' - For each category present in the candidates, pick up to 3 best scripts ranked highest first.',
  ' - For each pick output: { id, category, rank, title, body, rationale } where rationale is <=140 chars explaining why this fits the lead.',
  ' - Do NOT invent new scripts; only rank among the candidates supplied.',
  ' - If a category has no candidates, omit it.',
  ' - If lead niche mismatches all candidates, note that in rationale.',
  'Output shape: { "discovery":[...], "objection":[...], "closing":[...], "followup":[...], "competitor":[...] }'
].join('\n');

const user_prompt = [
  'LEAD CONTEXT:',
  JSON.stringify(ctx.lead_ctx, null, 2),
  '',
  'CLIENT CONTEXT:',
  JSON.stringify(ctx.client_ctx, null, 2),
  '',
  'STAGE HINT: ' + (ctx.stage || '(none)'),
  'SITUATION HINT: ' + (ctx.situation_hint || '(none)'),
  '',
  'CANDIDATE SCRIPTS:',
  JSON.stringify(buckets, null, 2),
  '',
  'Return the ranked JSON now.'
].join('\n');

return { json: {
  lead_id: ctx.lead_id,
  niche: ctx.niche,
  stage: ctx.stage,
  buckets,
  system_prompt,
  user_prompt,
  lead_ctx: ctx.lead_ctx,
  client_ctx: ctx.client_ctx
} };

// Parse Claude response; fallback to naive rank if Claude returns malformed JSON or is unbound
const resp = $input.item.json || {};
const prep = $('Prep Claude Prompt').first().json;

let ranked = null;
try {
  const text = (resp.content && resp.content[0] && resp.content[0].text) || '';
  if (text.trim().length > 0) ranked = JSON.parse(text.trim());
} catch (e) { ranked = null; }

// Fallback: trust the RPC's existing order (confidence desc) and cap at 3 per bucket
if (!ranked || typeof ranked !== 'object') {
  ranked = {};
  for (const cat of Object.keys(prep.buckets || {})) {
    const arr = (prep.buckets[cat] || []).slice(0, 3);
    ranked[cat] = arr.map(function(r, i) {
      return {
        id: r.script_id,
        category: r.script_category,
        rank: i + 1,
        title: r.script_title || '',
        body: r.script_body || '',
        rationale: 'Baseline RPC rank (Claude unavailable)'
      };
    });
  }
}

return { json: {
  ok: true,
  lead_id: prep.lead_id,
  context: { niche: prep.niche, stage: prep.stage, lead: prep.lead_ctx, client: prep.client_ctx },
  scripts: ranked
} };
